// W120 - auth_check + check_audio_size + normalize_input + context_id validation
// Consolidado en 1 nodo para reducir latencia.

const headers = $input.item.json.headers || {};
const authHeader = headers.authorization || headers.Authorization;
const expected = `Bearer ${$env.N8N_VOICE_TOKEN}`;

if (!authHeader || authHeader !== expected) {
  return { json: {
    __early_exit: true, ok: false, trace_id: null,
    error_code: 'AUTH_FAILED',
    error_message: 'Sesion expirada, recarga la app',
    timings: { total_ms: 0 },
  }};
}

// trace_id: vox_<timestamp36>_<rand8>
const traceId = 'vox_' + Date.now().toString(36) + '_' +
  Math.random().toString(36).substring(2, 10);
const t_start = Date.now();

const body = $input.item.json.body || $input.item.json;
const contextId = body.context_id || body['context_id'];
const rawMeta = body.metadata ?? '{}';
let metadata = {};
try { metadata = typeof rawMeta === 'string' ? JSON.parse(rawMeta) : rawMeta; } catch {}

// Whitelist de context_id (hardening). Ampliada en Paso 2 para rolito,
// extendida en Batch B con cierre_bolsas + reconciliacion_pt.
const ALLOWED_CONTEXTS = new Set([
  'form_merma',
  'form_empaque_rolito',
  'form_incidencia_rolito',
  'form_cierre_bolsas',
  'form_reconciliacion_pt',
  'form_harvest_barra',
  'form_tank_incident_barra',
  'form_almacen_pt_merma',
  'form_brine_reading',
]);
if (!contextId || !ALLOWED_CONTEXTS.has(contextId)) {
  return { json: {
    __early_exit: true, ok: false, trace_id: traceId,
    error_code: 'INTERNAL_ERROR',
    error_message: 'context_id desconocido',
    timings: { total_ms: Date.now() - t_start },
    meta: { received_context_id: contextId || null },
  }};
}

// Audio size guard (hardening). Frontend ya limita a 1MB; aqui defense-in-depth.
const bin = $input.item.binary || {};
const audioKey = Object.keys(bin)[0];
const audio = audioKey ? bin[audioKey] : null;
if (!audio) {
  return { json: {
    __early_exit: true, ok: false, trace_id: traceId,
    error_code: 'INTERNAL_ERROR',
    error_message: 'audio ausente en el request',
    timings: { total_ms: Date.now() - t_start },
  }};
}
const approxBytes = audio.fileSize || (audio.data ? Math.floor(audio.data.length * 0.75) : 0);
if (approxBytes > 1_000_000) {
  return { json: {
    __early_exit: true, ok: false, trace_id: traceId,
    error_code: 'AUDIO_TOO_LARGE',
    error_message: 'Audio muy largo, max 10 segundos',
    timings: { total_ms: Date.now() - t_start },
    meta: { audio_bytes: approxBytes },
  }};
}

return {
  json: {
    trace_id: traceId,
    context_id: contextId,
    plaza_id: metadata.plaza_id,
    user_id: metadata.user_id,
    canal: metadata.canal,
    metadata,
    timestamp: body.timestamp,
    t_start,
    audio_bytes: approxBytes,
    audio_key: audioKey,
  },
  binary: $input.item.binary,
};

// W120 - extract_transcript + early exit si empty/low confidence
const results = $input.item.json.results;
const alt = results?.channels?.[0]?.alternatives?.[0];
const transcript = (alt?.transcript || '').trim();
const confidence = alt?.confidence ?? 0;
const ctx = $('auth_context_size_gate').first().json;
const stt_ms = Date.now() - ctx.t_start;

if (transcript.length === 0) {
  return { json: {
    __early_exit: true, ok: false, trace_id: ctx.trace_id,
    error_code: 'STT_EMPTY',
    error_message: 'No detecte voz, intenta de nuevo',
    timings: { stt_ms, total_ms: stt_ms },
    meta: { stt_confidence: confidence, transcript: '' },
  }};
}
if (confidence < 0.6) {
  return { json: {
    __early_exit: true, ok: false, trace_id: ctx.trace_id,
    error_code: 'STT_LOW_CONFIDENCE',
    error_message: 'No se entendio bien, intenta de nuevo',
    timings: { stt_ms, total_ms: stt_ms },
    meta: { stt_confidence: confidence, transcript },
  }};
}
return { json: { ...ctx, transcript, stt_confidence: confidence, stt_ms } };

// W120 - load_context_config (dispatcher by context_id)
// Pre-build OpenAI body as string (n8n expression parser no maneja JSON
// deeply nested con expressions).
// form_merma se mantiene intacto. Agregados: form_empaque_rolito,
// form_incidencia_rolito. Cada context encapsula resolveCatalog,
// getSchema y buildSystemPrompt en su propia entrada de CONFIGS.

const ctx = $('extract_transcript').first().json;
const staticData = $getWorkflowStaticData('global');

// ─── CONFIGS por context_id ───────────────────────────────────────────────
const CONFIGS = {
  form_merma: {
    resolveCatalog(c, sd) {
      const cat = sd[`cat_${c.plaza_id}`] || { skus: [] };
      const empty = !Array.isArray(cat.skus) || cat.skus.length === 0;
      // Compat historica: en form_merma, cat vacio NO es error; solo marca
      // `catalog_fallback:true` y el LLM extrae raw sin ids.
      return { catalog: cat, empty, fallback: empty, version: cat.version || null };
    },
    getSchema() {
      return {
        name: 'merma_payload',
        strict: true,
        schema: {
          type: 'object',
          additionalProperties: false,
          required: ['product_id', 'raw_product_name', 'cantidad', 'unidad', 'motivo', 'confianza'],
          properties: {
            product_id: { type: ['integer', 'null'] },
            raw_product_name: { type: 'string' },
            cantidad: { type: 'number' },
            unidad: { type: 'string', enum: ['pza', 'bolsa', 'kg', 'tonelada'] },
            motivo: { type: 'string', enum: ['derretimiento', 'contaminacion', 'golpe', 'robo', 'otro'] },
            confianza: { type: 'number', minimum: 0, maximum: 1 },
          },
        },
      };
    },
    buildSystemPrompt(c, catalog) {
      return `Eres un extractor de datos para registrar mermas de hielo en plaza ${c.plaza_id || 'desconocida'}. Catalogo: ${JSON.stringify(catalog)}. Si no identificas SKU con alta confianza, product_id: null y raw_product_name con el nombre dicho. Nunca inventes IDs.`;
    },
  },

  form_empaque_rolito: {
    resolveCatalog(c /*, sd */) {
      const meta = c.metadata || {};
      let products = Array.isArray(meta.packing_products) ? meta.packing_products : [];
      if (products.length > 40) products = products.slice(0, 40);
      const empty = products.length === 0;
      return {
        catalog: { products, version: meta.catalog_version || null },
        empty,
        fallback: false,
        version: meta.catalog_version || null,
      };
    },
    getSchema() {
      return {
        name: 'empaque_rolito_payload',
        strict: true,
        schema: {
          type: 'object',
          additionalProperties: false,
          required: ['product_id', 'raw_product_name', 'qty_bags', 'cycle_num', 'confianza'],
          properties: {
            product_id: { type: ['integer', 'null'] },
            raw_product_name: { type: 'string' },
            qty_bags: { type: 'integer', minimum: 1, maximum: 999 },
            cycle_num: { type: ['integer', 'null'] },
            confianza: { type: 'number', minimum: 0, maximum: 1 },
          },
        },
      };
    },
    buildSystemPrompt(c, catalog) {
      return `Eres un extractor para registrar empaque de bolsas en linea rolito. Productos disponibles: ${JSON.stringify(catalog.products || [])}. El usuario dice cantidad de bolsas, tipo de producto, y opcionalmente numero de ciclo. Si identificas el producto con alta confianza, usa su id. Si no, product_id:null y raw_product_name con lo dicho. cycle_num es el numero de ciclo dentro del turno (1, 2, 3...). Nunca inventes IDs.`;
    },
  },

  form_incidencia_rolito: {
    resolveCatalog(c /*, sd */) {
      const meta = c.metadata || {};
      const downtime = Array.isArray(meta.downtime_categories) ? meta.downtime_categories : [];
      const scrap = Array.isArray(meta.scrap_reasons) ? meta.scrap_reasons : [];
      const empty = downtime.length === 0 && scrap.length === 0;
      return {
        catalog: { downtime_categories: downtime, scrap_reasons: scrap, version: meta.catalog_version || null },
        empty,
        fallback: false,
        version: meta.catalog_version || null,
      };
    },
    getSchema() {
      return {
        name: 'incidencia_rolito_payload',
        strict: true,
        schema: {
          type: 'object',
          additionalProperties: false,
          required: ['mode', 'category_id', 'category_name', 'kg_lost', 'minutes', 'notas', 'confianza'],
          properties: {
            mode: { type: 'string', enum: ['paro', 'merma'] },
            category_id: { type: ['integer', 'null'] },
            category_name: { type: 'string' },
            kg_lost: { type: ['number', 'null'] },
            minutes: { type: ['integer', 'null'] },
            notas: { type: 'string' },
            confianza: { type: 'number', minimum: 0, maximum: 1 },
          },
        },
      };
    },
    buildSystemPrompt(c, catalog) {
      return `Eres un extractor para incidencias de produccion en linea rolito. Primero determina "mode": "paro" (maquina detenida) o "merma" (producto defectuoso). Si mode="paro", category_id debe ser un id de: ${JSON.stringify(catalog.downtime_categories || [])}. Si mode="merma", category_id debe ser un id de: ${JSON.stringify(catalog.scrap_reasons || [])}. Para merma incluye kg_lost (>0). Para paro incluye minutes si el usuario lo menciona. category_name es el nombre literal identificado (sirve de fallback si el id no matchea). Nunca inventes IDs.`;
    },
  },

  form_cierre_bolsas: {
    // Sin catalogo externo: ambos campos son numericos directos.
    resolveCatalog() {
      return { catalog: {}, empty: false, fallback: false, version: null };
    },
    getSchema() {
      return {
        name: 'cierre_bolsas_payload',
        strict: true,
        schema: {
          type: 'object',
          additionalProperties: false,
          required: ['bags_received', 'bags_remaining', 'confianza'],
          properties: {
            bags_received: { type: ['integer', 'null'] },
            bags_remaining: { type: ['integer', 'null'] },
            confianza: { type: 'number', minimum: 0, maximum: 1 },
          },
        },
      };
    },
    buildSystemPrompt() {
      return `Eres un extractor para el cierre de turno rolito. El usuario dice cuantas bolsas recibio al inicio del turno y cuantas le sobraron al cierre. Devuelve bags_received (int) y bags_remaining (int). Si el usuario solo menciona uno, el otro debe ser null. Rango razonable 0-10000. No inventes numeros.`;
    },
  },

  form_reconciliacion_pt: {
    // Sin catalogo externo: un solo campo numerico decimal.
    resolveCatalog() {
      return { catalog: {}, empty: false, fallback: false, version: null };
    },
    getSchema() {
      return {
        name: 'reconciliacion_pt_payload',
        strict: true,
        schema: {
          type: 'object',
          additionalProperties: false,
          required: ['pt_received_kg', 'confianza'],
          properties: {
            pt_received_kg: { type: ['number', 'null'] },
            confianza: { type: 'number', minimum: 0, maximum: 1 },
          },
        },
      };
    },
    buildSystemPrompt() {
      return `Eres un extractor para reconciliacion de inventario PT. El usuario dice los kilos recibidos de produccion al almacen (numero decimal). Devuelve pt_received_kg (number). Si no se menciona un numero claro, null. Rango razonable 0-10000. No inventes numeros.`;
    },
  },

  form_harvest_barra: {
    // Sin catalogo externo: un solo campo numerico decimal (temperatura en °C).
    resolveCatalog() {
      return { catalog: {}, empty: false, fallback: false, version: null };
    },
    getSchema() {
      return {
        name: 'harvest_barra_payload',
        strict: true,
        schema: {
          type: 'object',
          additionalProperties: false,
          required: ['temperature', 'confianza'],
          properties: {
            temperature: { type: ['number', 'null'] },
            confianza: { type: 'number', minimum: 0, maximum: 1 },
          },
        },
      };
    },
    buildSystemPrompt() {
      return `Eres un extractor para registrar la temperatura de salmuera al cosechar una canastilla. El usuario dice la temperatura en grados Celsius; la salmuera suele ser NEGATIVA (tipico -10 a -15 °C). Devuelve temperature (number decimal, puede ser negativo, cero o positivo). Si no se menciona un numero claro de temperatura, null. Rango razonable -25 a 10. No inventes numeros.`;
    },
  },

  form_tank_incident_barra: {
    resolveCatalog(c /*, sd */) {
      const meta = c.metadata || {};
      const incidents = Array.isArray(meta.tank_incidents) ? meta.tank_incidents : [];
      // Catalogo es pequeño (5 tipos) — si viene vacio, EMPTY_CATALOG.
      return {
        catalog: { tank_incidents: incidents, version: meta.catalog_version || null },
        empty: incidents.length === 0,
        fallback: false,
        version: meta.catalog_version || null,
      };
    },
    getSchema() {
      return {
        name: 'tank_incident_barra_payload',
        strict: true,
        schema: {
          type: 'object',
          additionalProperties: false,
          required: ['incident_type_id', 'incident_type', 'description', 'confianza'],
          properties: {
            incident_type_id: { type: ['string', 'null'] },
            incident_type: { type: 'string' },
            description: { type: 'string' },
            confianza: { type: 'number', minimum: 0, maximum: 1 },
          },
        },
      };
    },
    buildSystemPrompt(c, catalog) {
      return `Eres un extractor para reportar incidentes en un tanque de salmuera. Tipos posibles (elige EXACTAMENTE UNO por id): ${JSON.stringify(catalog.tank_incidents || [])}. Devuelve incident_type_id (string con el id del catalogo si identificas con alta confianza, o null si no estas seguro), incident_type (el label formal del catalogo si matcheaste id, o el termino literal que dijo el usuario como fallback), description (texto libre de detalle que dijo el usuario, o string vacio si no dio detalles). Si el usuario no menciona ningun incidente, incident_type_id:null e incident_type:''. Nunca inventes IDs que no esten en la lista.`;
    },
  },

  form_almacen_pt_merma: {
    resolveCatalog(c /*, sd */) {
      const meta = c.metadata || {};
      const reasons = Array.isArray(meta.scrap_reasons) ? meta.scrap_reasons : [];
      let skus = Array.isArray(meta.skus) ? meta.skus : [];
      if (skus.length > 40) skus = skus.slice(0, 40);
      // Las 5 razones son estables (hardcoded en frontend). Si vienen vacias
      // marcamos empty para forzar EMPTY_CATALOG — no queremos extraer reason_id
      // sin whitelist viva.
      return {
        catalog: { reasons, skus, version: meta.catalog_version || null },
        empty: reasons.length === 0,
        fallback: false,
        version: meta.catalog_version || null,
      };
    },
    getSchema() {
      return {
        name: 'form_almacen_pt_merma_payload',
        strict: true,
        schema: {
          type: 'object',
          additionalProperties: false,
          required: ['product_id', 'raw_product_name', 'qty', 'reason_id', 'notes', 'confianza'],
          properties: {
            product_id: { type: ['integer', 'null'] },
            raw_product_name: { type: 'string' },
            qty: { type: ['number', 'null'] },
            reason_id: { type: ['string', 'null'] },
            notes: { type: 'string' },
            confianza: { type: 'number', minimum: 0, maximum: 1 },
          },
        },
      };
    },
    buildSystemPrompt(c, catalog) {
      const skus = Array.isArray(catalog.skus) ? catalog.skus : [];
      const reasons = Array.isArray(catalog.reasons) ? catalog.reasons : [];
      return `Eres un extractor para registrar merma de producto terminado en almacen (inventario ya listo, NO produccion). Productos disponibles: ${JSON.stringify(skus)}. Motivos posibles (elige EXACTAMENTE UNO por id, usando los aliases como pistas): ${JSON.stringify(reasons)}. El usuario dice: producto (nombre o SKU), qty (cantidad en unidades, numero), motivo (por que la merma) y opcionalmente notas. Si identificas el producto con alta confianza usa su id; si no, product_id:null y raw_product_name con el nombre dicho. Para el motivo elige el id del catalogo que mejor matchee con lo dicho (aliases incluidos); si nada matchea o el usuario no menciona motivo, reason_id:null. notes es texto libre de detalle (o string vacio). qty debe ser number > 0 si el usuario lo dice; si no, null. Nunca inventes IDs.`;
    },
  },

  form_brine_reading: {
    // Sin catalogo externo: 2 campos numericos (saltLevel + brineTemp).
    resolveCatalog() {
      return { catalog: {}, empty: false, fallback: false, version: null };
    },
    getSchema() {
      return {
        name: 'brine_reading_payload',
        strict: true,
        schema: {
          type: 'object',
          additionalProperties: false,
          required: ['saltLevel', 'brineTemp', 'confianza'],
          properties: {
            saltLevel: { type: ['number', 'null'] },
            brineTemp: { type: ['number', 'null'] },
            confianza: { type: 'number', minimum: 0, maximum: 1 },
          },
        },
      };
    },
    buildSystemPrompt() {
      return `Eres un extractor de lecturas de salmuera de tanques de hielo. El supervisor dice DOS valores numericos:\n- saltLevel: nivel de sal, unidades ppm o %. Palabras clave: 'sal', 'nivel', 'ppm'. Rango razonable 0-10000.\n- brineTemp: temperatura de la salmuera en grados Celsius. Palabras clave: 'temperatura', 'temp', 'grados'. Rango razonable -25 a 10; tipicamente NEGATIVA (entre -10 y -15).\n\nREGLAS DE EXTRACCION:\n1. PRIORIZA keywords. Ejemplos:\n   - '500 ppm' o 'sal a 500' o '500 de sal' -> saltLevel=500.\n   - 'menos 13 grados' o 'temperatura menos 13' o '-13 grados' -> brineTemp=-13.\n2. FALLBACK por orden: si NO hay keywords pero hay dos numeros, el PRIMERO es saltLevel y el SEGUNDO es brineTemp.\n3. NO MEZCLES los valores. Si solo hay keyword para uno, devuelve solo ese; el otro debe ser null.\n4. 'Menos N', 'negativo N' o 'bajo cero N' significa -N (solo aplica a brineTemp; saltLevel siempre >= 0).\n5. Si el usuario no dice ningun numero claro, ambos null.\n\nEJEMPLOS:\n- 'quinientos ppm, menos trece grados' -> { saltLevel: 500, brineTemp: -13 }\n- 'sal a 500, temperatura menos 13' -> { saltLevel: 500, brineTemp: -13 }\n- '500 de sal, -13 grados' -> { saltLevel: 500, brineTemp: -13 }\n- 'mil ppm' -> { saltLevel: 1000, brineTemp: null }\n- 'menos doce grados' -> { saltLevel: null, brineTemp: -12 }\n- '800 y menos 10' (sin keywords) -> { saltLevel: 800, brineTemp: -10 }\n\nNunca inventes valores.`;
    },
  },
};

// ─── dispatcher ────────────────────────────────────────────────────────────
const cfg = CONFIGS[ctx.context_id];
if (!cfg) {
  // auth_context_size_gate ya valida whitelist; guardia defensiva.
  return { json: {
    ...ctx,
    __validation_failed: true, ok: false, trace_id: ctx.trace_id,
    error_code: 'INTERNAL_ERROR',
    error_message: 'Config ausente para context_id',
    errors: [`config_missing_${ctx.context_id}`],
    timings: { stt_ms: ctx.stt_ms, total_ms: Date.now() - ctx.t_start },
    meta: { stt_confidence: ctx.stt_confidence, transcript: ctx.transcript },
    // body minimal para que openai_extract no crashee; validate descarta por __validation_failed.
    openai_body: JSON.stringify({ model: 'gpt-4o-mini', messages: [{ role: 'user', content: 'ok' }], max_tokens: 1 }),
  }};
}

const { catalog, empty, fallback, version } = cfg.resolveCatalog(ctx, staticData);

// EMPTY_CATALOG: form_merma tolera catalog vacio (fallback historico).
// Los otros contexts fallan explicitamente antes de llamar al LLM.
if (empty && ctx.context_id !== 'form_merma') {
  return { json: {
    ...ctx,
    catalog, catalog_fallback: fallback, catalog_version: version,
    __validation_failed: true, ok: false, trace_id: ctx.trace_id,
    error_code: 'EMPTY_CATALOG',
    error_message: 'Catalogo ausente o vacio en metadata',
    errors: [`catalog_empty_${ctx.context_id}`],
    timings: { stt_ms: ctx.stt_ms, total_ms: Date.now() - ctx.t_start },
    meta: { stt_confidence: ctx.stt_confidence, transcript: ctx.transcript, catalog_fallback: fallback, catalog_version: version },
    openai_body: JSON.stringify({ model: 'gpt-4o-mini', messages: [{ role: 'user', content: 'ok' }], max_tokens: 1 }),
  }};
}

const openai_body = JSON.stringify({
  model: 'gpt-4o-mini',
  temperature: 0,
  messages: [
    { role: 'system', content: cfg.buildSystemPrompt(ctx, catalog) },
    { role: 'user', content: ctx.transcript || '' },
  ],
  response_format: { type: 'json_schema', json_schema: cfg.getSchema() },
});

return { json: {
  ...ctx,
  catalog,
  catalog_fallback: fallback,
  catalog_version: version,
  openai_body,
}};

// W120 - validate_business_rules (dispatcher por context_id)
// Whitelists y reglas de negocio por contexto. NO rechaza por confianza baja
// (la confianza solo se emite en el output). Short-circuit si load_catalog ya
// marco __validation_failed (ej. EMPTY_CATALOG).

const ctx = $('load_catalog').first().json;

// Short-circuit: load_catalog ya decidio envelope de error; solo propagar.
if (ctx.__validation_failed) return { json: ctx };

const validation_start = Date.now();

// Parse respuesta del LLM
let llmRaw;
try {
  const content = $input.item.json.choices?.[0]?.message?.content;
  llmRaw = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  return { json: {
    __validation_failed: true, ok: false, trace_id: ctx.trace_id,
    error_code: 'INTERNAL_ERROR',
    error_message: 'OpenAI response no parseable',
    errors: [String(e.message || e)],
    timings: { stt_ms: ctx.stt_ms, validation_ms: Date.now() - validation_start },
    meta: { stt_confidence: ctx.stt_confidence, transcript: ctx.transcript },
  }};
}
const llm_ms = Date.now() - ctx.t_start - ctx.stt_ms;

// ─── VALIDATORS por context_id ─────────────────────────────────────────────
const VALIDATORS = {
  form_merma(raw, c) {
    const errs = [];
    const ALLOWED_UNIDAD = new Set(['pza','bolsa','kg','tonelada']);
    const ALLOWED_MOTIVO = new Set(['derretimiento','contaminacion','golpe','robo','otro']);
    if (raw.unidad && !ALLOWED_UNIDAD.has(raw.unidad)) {
      errs.push(`unidad_fuera_whitelist: ${raw.unidad}`);
    }
    if (raw.motivo && !ALLOWED_MOTIVO.has(raw.motivo)) {
      errs.push(`motivo_fuera_whitelist: ${raw.motivo}`);
    }
    if (typeof raw.cantidad !== 'number' || raw.cantidad < 0.01 || raw.cantidad > 500) {
      errs.push(`cantidad_fuera_rango: ${raw.cantidad}`);
    }
    if (raw.product_id && c.catalog?.skus?.length) {
      const sku = c.catalog.skus.find(s => s.id === raw.product_id);
      if (sku && sku.uom && sku.uom !== raw.unidad) {
        errs.push(`unidad_incoherente: sku=${sku.uom} llm=${raw.unidad}`);
      }
    }
    return { errors: errs, error_code: errs.length ? 'VALIDATION_FAILED' : null };
  },

  form_empaque_rolito(/* raw, c */) {
    // Schema strict ya valida tipos (product_id int|null, qty_bags int 1-999,
    // cycle_num int|null, confianza 0-1). Ajuste 8: cycle_num NO se valida
    // contra catalogo aqui (es responsabilidad del matcher frontend).
    // Ajuste 5: no rechazar por confianza baja.
    return { errors: [], error_code: null };
  },

  form_incidencia_rolito(raw, c) {
    const errs = [];
    const cat = c.catalog || {};
    const downtimeIds = new Set((cat.downtime_categories || []).map(x => Number(x.id)));
    const scrapIds = new Set((cat.scrap_reasons || []).map(x => Number(x.id)));
    // kg_lost requerido para merma
    if (raw.mode === 'merma' && (typeof raw.kg_lost !== 'number' || raw.kg_lost <= 0)) {
      errs.push(`kg_lost_requerido_merma: ${raw.kg_lost}`);
    }
    // MODE_CATEGORY_MISMATCH si category_id no existe en el catalogo del mode
    if (raw.category_id !== null && raw.category_id !== undefined) {
      const cid = Number(raw.category_id);
      if (raw.mode === 'paro' && !downtimeIds.has(cid)) {
        return { errors: [`category_id_no_en_downtime: ${cid}`], error_code: 'MODE_CATEGORY_MISMATCH' };
      }
      if (raw.mode === 'merma' && !scrapIds.has(cid)) {
        return { errors: [`category_id_no_en_scrap: ${cid}`], error_code: 'MODE_CATEGORY_MISMATCH' };
      }
    }
    return { errors: errs, error_code: errs.length ? 'VALIDATION_FAILED' : null };
  },

  form_cierre_bolsas(raw /*, c */) {
    // Ajuste Batch B: ambos null -> VALIDATION_FAILED (el usuario no capturo ningun dato).
    if (raw.bags_received === null && raw.bags_remaining === null) {
      return { errors: ['ningun_dato_capturado'], error_code: 'VALIDATION_FAILED' };
    }
    return { errors: [], error_code: null };
  },

  form_reconciliacion_pt(raw /*, c */) {
    // Ajuste Batch B: pt_received_kg null -> VALIDATION_FAILED (campo unico requerido).
    if (raw.pt_received_kg === null || raw.pt_received_kg === undefined) {
      return { errors: ['pt_received_kg_requerido'], error_code: 'VALIDATION_FAILED' };
    }
    return { errors: [], error_code: null };
  },

  form_harvest_barra(raw /*, c */) {
    // Piloto barra 1: temperature null -> VALIDATION_FAILED (campo unico requerido).
    // Cero y negativos son validos (salmuera tipica -10 a -15 °C).
    if (raw.temperature === null || raw.temperature === undefined || typeof raw.temperature !== 'number' || isNaN(raw.temperature)) {
      return { errors: ['temperature_requerido'], error_code: 'VALIDATION_FAILED' };
    }
    return { errors: [], error_code: null };
  },

  form_tank_incident_barra(raw /*, c */) {
    // Piloto barra 2: incident_type_id null Y description vacia -> VALIDATION_FAILED.
    // Al menos uno de los dos debe venir para que el reporte tenga sentido.
    const idEmpty = raw.incident_type_id === null || raw.incident_type_id === undefined || raw.incident_type_id === '';
    const descEmpty = typeof raw.description !== 'string' || raw.description.trim() === '';
    if (idEmpty && descEmpty) {
      return { errors: ['sin_tipo_ni_descripcion'], error_code: 'VALIDATION_FAILED' };
    }
    return { errors: [], error_code: null };
  },

  form_almacen_pt_merma(raw /*, c */) {
    const ALLOWED_REASONS = new Set(['damage', 'expired', 'shortage', 'contamination', 'other']);
    // reason_id fuera de whitelist (LLM alucinado) -> error explicito.
    if (raw.reason_id && !ALLOWED_REASONS.has(raw.reason_id)) {
      return { errors: [`reason_id_fuera_whitelist: ${raw.reason_id}`], error_code: 'VALIDATION_FAILED' };
    }
    // Bloquear si NINGUN campo utilizable llego — el usuario no dicto nada real.
    const noProduct = (raw.product_id === null || raw.product_id === undefined) &&
                      (typeof raw.raw_product_name !== 'string' || raw.raw_product_name.trim() === '');
    const noQty = typeof raw.qty !== 'number' || raw.qty <= 0;
    const noReason = !raw.reason_id;
    const noNotes = typeof raw.notes !== 'string' || raw.notes.trim() === '';
    if (noProduct && noQty && noReason && noNotes) {
      return { errors: ['ningun_dato_capturado'], error_code: 'VALIDATION_FAILED' };
    }
    // qty presente debe caer en rango razonable para merma PT.
    if (typeof raw.qty === 'number' && raw.qty > 0 && (raw.qty < 0.01 || raw.qty > 500)) {
      return { errors: [`qty_fuera_rango: ${raw.qty}`], error_code: 'VALIDATION_FAILED' };
    }
    return { errors: [], error_code: null };
  },

  form_brine_reading(raw /*, c */) {
    const saltNull = raw.saltLevel === null || raw.saltLevel === undefined;
    const tempNull = raw.brineTemp === null || raw.brineTemp === undefined;
    // Si ambos null, el usuario no dicto ningun numero aprovechable.
    if (saltNull && tempNull) {
      return { errors: ['ningun_valor_capturado'], error_code: 'VALIDATION_FAILED' };
    }
    // Rangos razonables por campo. saltLevel siempre >= 0.
    if (!saltNull && (typeof raw.saltLevel !== 'number' || raw.saltLevel < 0 || raw.saltLevel > 10000)) {
      return { errors: [`saltLevel_fuera_rango: ${raw.saltLevel}`], error_code: 'VALIDATION_FAILED' };
    }
    if (!tempNull && (typeof raw.brineTemp !== 'number' || raw.brineTemp < -25 || raw.brineTemp > 10)) {
      return { errors: [`brineTemp_fuera_rango: ${raw.brineTemp}`], error_code: 'VALIDATION_FAILED' };
    }
    return { errors: [], error_code: null };
  },
};

const validator = VALIDATORS[ctx.context_id];
const result = validator
  ? validator(llmRaw, ctx)
  : { errors: [`no_validator_para_${ctx.context_id}`], error_code: 'INTERNAL_ERROR' };

const validation_ms = Date.now() - validation_start;

if (result.error_code) {
  const msg = result.error_code === 'MODE_CATEGORY_MISMATCH'
    ? 'Categoria no corresponde al tipo de incidencia'
    : 'Revisa los datos manualmente';
  return { json: {
    __validation_failed: true, ok: false, trace_id: ctx.trace_id,
    error_code: result.error_code,
    error_message: msg,
    errors: result.errors, ai_output: llmRaw,
    timings: { stt_ms: ctx.stt_ms, llm_ms, validation_ms },
    meta: { stt_confidence: ctx.stt_confidence, transcript: ctx.transcript, catalog_fallback: ctx.catalog_fallback, catalog_version: ctx.catalog_version },
  }};
}

return { json: { ...ctx, ai_output: llmRaw, llm_ms, validation_ms } };

// W120 - build_response (success path)
const ctx = $input.item.json;
if (ctx.__validation_failed) return { json: ctx }; // ya es envelope error

const total_ms = Date.now() - ctx.t_start;

// Confirmation text templates por context_id (ADR 0001 extension aditiva).
// Devuelven null si no hay suficientes campos -> meta.confirmation_text se
// omite y el frontend usa su banner legacy (transcript + confianza).
const CONFIRMATION_TEMPLATES = {
  form_merma(d) {
    if (!d) return null;
    const name = d.raw_product_name || null;
    const qty = (typeof d.cantidad === 'number' && d.cantidad > 0) ? d.cantidad : null;
    if (!qty || !name) return null;
    const unidad = d.unidad ? `${d.unidad}${d.cantidad === 1 ? '' : 's'}` : '';
    const motivo = d.motivo ? ` por ${d.motivo}` : '';
    return `Voy a registrar ${qty}${unidad ? ' ' + unidad : ''} de ${name}${motivo}`;
  },
  form_empaque_rolito(d) {
    if (!d) return null;
    const qty = (typeof d.qty_bags === 'number' && d.qty_bags > 0) ? d.qty_bags : null;
    if (!qty) return null;
    const name = d.raw_product_name ? ` de ${d.raw_product_name}` : '';
    const cycle = (typeof d.cycle_num === 'number') ? `, ciclo ${d.cycle_num}` : '';
    return `Voy a registrar empaque de ${qty} bolsas${name}${cycle}`;
  },
  form_incidencia_rolito(d) {
    if (!d) return null;
    const cat = d.category_name || null;
    if (d.mode === 'paro') {
      const min = (typeof d.minutes === 'number' && d.minutes > 0) ? `, ${d.minutes} minutos` : '';
      return cat ? `Voy a reportar paro por ${cat}${min}` : null;
    }
    if (d.mode === 'merma') {
      const kg = (typeof d.kg_lost === 'number' && d.kg_lost > 0) ? `, ${d.kg_lost} kg perdidos` : '';
      return cat ? `Voy a reportar merma ${cat}${kg}` : null;
    }
    return null;
  },
  form_cierre_bolsas(d) {
    if (!d) return null;
    const parts = [];
    if (typeof d.bags_received === 'number') parts.push(`${d.bags_received} recibidas`);
    if (typeof d.bags_remaining === 'number') parts.push(`${d.bags_remaining} sobrantes`);
    if (!parts.length) return null;
    return `Voy a registrar cuadratura: ${parts.join(', ')}`;
  },
  form_reconciliacion_pt(d) {
    if (!d) return null;
    if (typeof d.pt_received_kg !== 'number') return null;
    return `Voy a verificar ${d.pt_received_kg} kg recibidos`;
  },
  form_harvest_barra(d) {
    if (!d || typeof d.temperature !== 'number') return null;
    return `Voy a registrar cosecha con ${d.temperature} grados`;
  },
  form_tank_incident_barra(d) {
    if (!d) return null;
    const tipo = d.incident_type || null;
    if (!tipo) return null;
    const desc = (typeof d.description === 'string' && d.description.trim()) ? ` Observacion: ${d.description.trim()}` : '';
    return `Voy a reportar ${tipo} en el tanque.${desc}`;
  },
  form_almacen_pt_merma(d) {
    if (!d) return null;
    const name = d.raw_product_name || null;
    const qty = (typeof d.qty === 'number' && d.qty > 0) ? d.qty : null;
    if (!qty && !name && !d.reason_id) return null;
    const REASON_LABELS = {
      damage: 'roto o danado',
      expired: 'caducado',
      shortage: 'faltante',
      contamination: 'contaminacion',
      other: 'otro motivo',
    };
    const motivo = d.reason_id ? ` por ${REASON_LABELS[d.reason_id] || d.reason_id}` : '';
    if (qty && name) return `Voy a registrar ${qty} de ${name}${motivo}`;
    if (name) return `Voy a registrar merma de ${name}${motivo}`;
    if (qty) return `Voy a registrar ${qty} de merma${motivo}`;
    return `Voy a registrar merma${motivo}`;
  },
  form_brine_reading(d) {
    if (!d) return null;
    const salt = (typeof d.saltLevel === 'number') ? d.saltLevel : null;
    const temp = (typeof d.brineTemp === 'number') ? d.brineTemp : null;
    if (salt === null && temp === null) return null;
    const parts = [];
    if (salt !== null) parts.push(`sal en ${salt} ppm`);
    if (temp !== null) parts.push(`temperatura en ${temp} grados`);
    return `Voy a registrar ${parts.join(' y ')}.`;
  },
};

let confirmation_text = null;
try {
  const fn = CONFIRMATION_TEMPLATES[ctx.context_id];
  if (fn) confirmation_text = fn(ctx.ai_output);
} catch { confirmation_text = null; }

const meta = {
  stt_confidence: ctx.stt_confidence,
  transcript: ctx.transcript,
  catalog_fallback: !!ctx.catalog_fallback,
  catalog_version: ctx.catalog_version || null,
};
if (confirmation_text) meta.confirmation_text = confirmation_text;

return { json: {
  ok: true,
  trace_id: ctx.trace_id,
  context_id: ctx.context_id,
  schema_version: 'v1',
  prompt_version: `${ctx.context_id}_v1.0`,
  pipeline_version: 'w120_v2.0',
  data: ctx.ai_output,
  timings: {
    stt_ms: ctx.stt_ms,
    llm_ms: ctx.llm_ms || 0,
    validation_ms: ctx.validation_ms || 0,
    total_ms,
  },
  meta,
}};

// W120 - log_fail_notice: console.log si log_to_odoo fallo (hardening aprobado)
const resp = $input.item.json;
if (resp?.error || resp?.result?.error) {
  const env = $('build_response').first().json || {};
  const safeTranscript = (env?.meta?.transcript || '').slice(0, 100);
  console.log('[W120 log_to_odoo FAIL]',
    'trace_id=' + env?.trace_id,
    'ok=' + env?.ok,
    'transcript="' + safeTranscript + '"',
    'odoo_error=' + JSON.stringify(resp?.error || resp?.result?.error)
  );
}
return $input.item;
